"use strict";(self.webpackChunkrgbds_www=self.webpackChunkrgbds_www||[]).push([[5335],{28453:(e,a,s)=>{s.d(a,{R:()=>r,x:()=>l});var n=s(96540);const c={},d=n.createContext(c);function r(e){const a=n.useContext(d);return n.useMemo((function(){return"function"==typeof e?e(a):{...a,...e}}),[a,e])}function l(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(c):e.components||c:r(e.components),n.createElement(d.Provider,{value:a},e.children)}},60401:(e,a,s)=>{s.r(a),s.d(a,{assets:()=>t,contentTitle:()=>o,default:()=>m,frontMatter:()=>l,metadata:()=>n,toc:()=>i});const n=JSON.parse('{"id":"rgbasm.1","title":"rgbasm(1) \u2014 Game Boy assembler","description":"","source":"@site/versioned_docs/version-v0.9.2/rgbasm.1.md","sourceDirName":".","slug":"/rgbasm.1","permalink":"/docs/v0.9.2/rgbasm.1","draft":false,"unlisted":false,"editUrl":"https://github.com/gbdev/rgbds/edit/master/man/rgbasm.1","tags":[],"version":"v0.9.2","frontMatter":{},"sidebar":"nav","previous":{"title":"Object file format","permalink":"/docs/v0.9.2/rgbds.5"},"next":{"title":"RGBLINK","permalink":"/docs/v0.9.2/rgblink.1"}}');var c=s(74848),d=s(28453);const r='<section class="Sh">\n<h2 class="Sh" id="SYNOPSIS"><a class="permalink" href="#SYNOPSIS">SYNOPSIS</a></h2>\n<table class="Nm">\n  <tr>\n    <td><code class="Nm">rgbasm</code></td>\n    <td>[<code class="Fl"><a href="#E">-E</a><a href="#h">h</a><a href="#V">V</a><a href="#v">v</a><a href="#w">w</a></code>] [<code class="Fl"><a href="#b">-b</a></code>\n      <var class="Ar">chars</var>] [<code class="Fl"><a href="#D">-D</a></code>\n      <var class="Ar">name</var>[=<var class="Ar">value</var>]]\n      [<code class="Fl"><a href="#g">-g</a></code> <var class="Ar">chars</var>]\n      [<code class="Fl"><a href="#I">-I</a></code> <var class="Ar">path</var>]\n      [<code class="Fl"><a href="#M">-M</a></code> <var class="Ar">depend_file</var>]\n      [<code class="Fl"><a href="#M">-M</a><a href="#G">G</a></code>] [<code class="Fl"><a href="#M">-M</a><a href="#P">P</a></code>]\n      [<code class="Fl"><a href="#M">-M</a><a href="#T">T</a></code> <var class="Ar">target_file</var>]\n      [<code class="Fl"><a href="#M">-M</a><a href="#Q">Q</a></code> <var class="Ar">target_file</var>]\n      [<code class="Fl"><a href="#o">-o</a></code> <var class="Ar">out_file</var>]\n      [<code class="Fl"><a href="#P">-P</a></code> <var class="Ar">include_file</var>]\n      [<code class="Fl"><a href="#p">-p</a></code> <var class="Ar">pad_value</var>]\n      [<code class="Fl"><a href="#Q">-Q</a></code> <var class="Ar">fix_precision</var>]\n      [<code class="Fl"><a href="#r">-r</a></code> <var class="Ar">recursion_depth</var>]\n      [<code class="Fl"><a href="#s">-s</a></code>\n      <var class="Ar">features</var>:<var class="Ar">state_file</var>]\n      [<code class="Fl"><a href="#W">-W</a></code> <var class="Ar">warning</var>]\n      [<code class="Fl"><a href="#X">-X</a></code> <var class="Ar">max_errors</var>]\n      <var class="Ar">asmfile</var></td>\n  </tr>\n</table>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="DESCRIPTION"><a class="permalink" href="#DESCRIPTION">DESCRIPTION</a></h2>\n<p class="Pp">The <code class="Nm">rgbasm</code> program creates an RGB object\n    file from an assembly source file. The object file format is documented in\n    <a class="Xr" href="./rgbds.5">rgbds(5)</a>.</p>\n<p class="Pp">The input <var class="Ar">asmfile</var> can be a path to a file,\n    or <code class="Cm">-</code> to read from standard input.</p>\n<p class="Pp">Note that options can be abbreviated as long as the abbreviation\n    is unambiguous: <code class="Fl">--verb</code> is\n    <code class="Fl">--verbose</code>, but <code class="Fl">--ver</code> is\n    invalid because it could also be <code class="Fl">--version</code>. The\n    arguments are as follows:</p>\n<dl class="Bl-tag">\n  <dt id="b"><a class="permalink" href="#b"><code class="Fl">-b</code></a>\n    <var class="Ar">chars</var>, <code class="Fl">--binary-digits</code>\n    <var class="Ar">chars</var></dt>\n  <dd>Change the two characters used for binary constants. The defaults are\n    01.</dd>\n  <dt id="D"><a class="permalink" href="#D"><code class="Fl">-D</code></a>\n    <var class="Ar">name</var>[=<var class="Ar">value</var>],\n    <code class="Fl">--define</code>\n    <var class="Ar">name</var>[=<var class="Ar">value</var>]</dt>\n  <dd>Add a string symbol to the compiled source code. This is equivalent to\n      &#x2018;<code class="Li"><var class="Ar">name</var>\n      <code class="Ic">EQUS</code>\n      <span class="No">&quot;</span><var class="Ar">value</var>&quot;</code>&#x2019;\n      in code, or &#x2018;<code class="Li"><var class="Ar">name</var>\n      <code class="Ic">EQUS</code>\n      <span class="No">&quot;1&quot;</span></code>&#x2019; if\n      <var class="Ar">value</var> is not specified.</dd>\n  <dt id="E"><a class="permalink" href="#E"><code class="Fl">-E</code></a>,\n    <code class="Fl">--export-all</code></dt>\n  <dd>Export all labels, including unreferenced and local labels.</dd>\n  <dt id="g"><a class="permalink" href="#g"><code class="Fl">-g</code></a>\n    <var class="Ar">chars</var>, <code class="Fl">--gfx-chars</code>\n    <var class="Ar">chars</var></dt>\n  <dd>Change the four characters used for gfx constants. The defaults are\n    0123.</dd>\n  <dt id="h"><a class="permalink" href="#h"><code class="Fl">-h</code></a>,\n    <code class="Fl">--help</code></dt>\n  <dd>Print help text for the program and exit.</dd>\n  <dt id="I"><a class="permalink" href="#I"><code class="Fl">-I</code></a>\n    <var class="Ar">path</var>, <code class="Fl">--include</code>\n    <var class="Ar">path</var></dt>\n  <dd>Add a new &#x201C;include path&#x201D;; <var class="Ar">path</var> must\n      point to a directory. When a <code class="Ic">INCLUDE</code> (including\n      the implicit one from <code class="Fl">-P</code>) or\n      <code class="Ic">INCBIN</code> is attempted,\n      <code class="Nm">rgbasm</code> first looks up the provided path from its\n      working directory; if this fails, it tries again from each of the\n      &#x201C;include path&#x201D; directories, in the order they were\n    provided.</dd>\n  <dt id="M"><a class="permalink" href="#M"><code class="Fl">-M</code></a>\n    <var class="Ar">depend_file</var>, <code class="Fl">--dependfile</code>\n    <var class="Ar">depend_file</var></dt>\n  <dd>Write\n      <a class="Xr" href="https://man7.org/linux/man-pages/man1/make.1.html">make(1)</a>\n      dependencies to <var class="Ar">depend_file</var>.</dd>\n  <dt id="MG"><a class="permalink" href="#MG"><code class="Fl">-MG</code></a></dt>\n  <dd>To be used in conjunction with <code class="Fl">-M</code>. This makes\n      <code class="Nm">rgbasm</code> assume that missing files are\n      auto-generated: when <code class="Ic">INCLUDE</code> (including the\n      implicit one from <code class="Fl">-P</code>) or\n      <code class="Ic">INCBIN</code> is attempted on a non-existent file, it is\n      added as a dependency, then <code class="Nm">rgbasm</code> exits normally\n      instead of erroring out. This feature is used in automatic updating of\n      makefiles.</dd>\n  <dt id="MP"><a class="permalink" href="#MP"><code class="Fl">-MP</code></a></dt>\n  <dd>When enabled, this causes a phony target to be added for each dependency\n      other than the main file. This prevents\n      <a class="Xr" href="https://man7.org/linux/man-pages/man1/make.1.html">make(1)</a>\n      from erroring out when dependency files are deleted.</dd>\n  <dt id="MT"><a class="permalink" href="#MT"><code class="Fl">-MT</code></a>\n    <var class="Ar">target_file</var></dt>\n  <dd>Add a target to the rules emitted by <code class="Fl">-M</code>. The exact\n      string provided will be written, including spaces and special characters.\n    <div class="Bd Bd-indent"><code class="Li"><code class="Fl">-MT</code>\n      <span class="No">fileA</span> <code class="Fl">-MT</code>\n      <span class="No">fileB</span></code></div>\n    is equivalent to\n    <div class="Bd Bd-indent"><code class="Li"><code class="Fl">-MT</code>\n      <span class="No">\'fileA fileB\'</span></code></div>\n    . If neither this nor <code class="Fl">-MQ</code> is specified, the output\n      file name is used.</dd>\n  <dt id="MQ"><a class="permalink" href="#MQ"><code class="Fl">-MQ</code></a>\n    <var class="Ar">target_file</var></dt>\n  <dd>Same as <code class="Fl">-MT</code>, but additionally escapes any special\n      <a class="Xr" href="https://man7.org/linux/man-pages/man1/make.1.html">make(1)</a>\n      characters, essentially &#x2018;$&#x2019;.</dd>\n  <dt id="o"><a class="permalink" href="#o"><code class="Fl">-o</code></a>\n    <var class="Ar">out_file</var>, <code class="Fl">--output</code>\n    <var class="Ar">out_file</var></dt>\n  <dd>Write an object file to the given filename.</dd>\n  <dt id="P"><a class="permalink" href="#P"><code class="Fl">-P</code></a>\n    <var class="Ar">include_file</var>, <code class="Fl">--preinclude</code>\n    <var class="Ar">include_file</var></dt>\n  <dd>Pre-include a file. This acts as if a\n      &#x2018;<code class="Li"><code class="Ic">INCLUDE</code>\n      &quot;<var class="Ar">include_file</var>&quot;</code>&#x2019; was read\n      before the input <var class="Ar">asmfile</var>.</dd>\n  <dt id="p"><a class="permalink" href="#p"><code class="Fl">-p</code></a>\n    <var class="Ar">pad_value</var>, <code class="Fl">--pad-value</code>\n    <var class="Ar">pad_value</var></dt>\n  <dd>Use this as the value for <code class="Ic">DS</code> directives in ROM\n      sections, unless overridden. The default is 0x00.</dd>\n  <dt id="Q"><a class="permalink" href="#Q"><code class="Fl">-Q</code></a>\n    <var class="Ar">fix_precision</var>, <code class="Fl">--q-precision</code>\n    <var class="Ar">fix_precision</var></dt>\n  <dd>Use this as the precision of fixed-point numbers after the decimal point,\n      unless they specify their own precision. The default is 16, so fixed-point\n      numbers are Q16.16 (since they are 32-bit integers). The argument may\n      start with a &#x2018;<code class="Li">.</code>&#x2019; to match the Q\n      notation, for example, &#x2018;<code class="Li"><code class="Fl">-Q</code>\n      <var class="Ar">.16</var></code>&#x2019;.</dd>\n  <dt id="r"><a class="permalink" href="#r"><code class="Fl">-r</code></a>\n    <var class="Ar">recursion_depth</var>,\n    <code class="Fl">--recursion-depth</code>\n    <var class="Ar">recursion_depth</var></dt>\n  <dd>Specifies the recursion depth past which <code class="Nm">rgbasm</code>\n      will assume being in an infinite loop. The default is 64.</dd>\n  <dt id="s"><a class="permalink" href="#s"><code class="Fl">-s</code></a>\n    <var class="Ar">features</var>:<var class="Ar">state_file</var>,\n    <code class="Fl">--state</code>\n    <var class="Ar">features</var>:<var class="Ar">state_file</var></dt>\n  <dd>Write the specified <var class="Ar">features</var> to\n      <var class="Ar">state_file</var>, based on the final state of\n      <code class="Nm">rgbasm</code> at the end of its input. The expected\n      <var class="Ar">features</var> are a comma-separated subset of the\n      following:\n    <dl class="Bl-tag">\n      <dt id="equ"><a class="permalink" href="#equ"><code class="Cm">equ</code></a></dt>\n      <dd>Write all numeric constants as\n          &#x2018;<code class="Li"><code class="Ic">def</code>\n          <var class="Ar">name</var> <code class="Ic">equ</code>\n          <var class="Ar">value</var></code>&#x2019;.</dd>\n      <dt id="var"><a class="permalink" href="#var"><code class="Cm">var</code></a></dt>\n      <dd>Write all variables as\n          &#x2018;<code class="Li"><code class="Ic">def</code>\n          <var class="Ar">name</var> <code class="Ic">=</code>\n          <var class="Ar">value</var></code>&#x2019;.</dd>\n      <dt id="equs"><a class="permalink" href="#equs"><code class="Cm">equs</code></a></dt>\n      <dd>Write all string constants as\n          &#x2018;<code class="Li"><code class="Ic">def</code>\n          <var class="Ar">name</var> <code class="Ic">equs</code>\n          &quot;<var class="Ar">value</var>&quot;</code>&#x2019;.</dd>\n      <dt id="char"><a class="permalink" href="#char"><code class="Cm">char</code></a></dt>\n      <dd>Write all characters as\n          &#x2018;<code class="Li"><code class="Ic">charmap</code>\n          <var class="Ar">name</var>,\n          <var class="Ar">value</var></code>&#x2019;.</dd>\n      <dt id="macro"><a class="permalink" href="#macro"><code class="Cm">macro</code></a></dt>\n      <dd>Write all macros as\n          &#x2018;<code class="Li"><code class="Ic">macro</code>\n          <var class="Ar">name</var> <span class="No">...</span>\n          <code class="Ic">endm</code></code>&#x2019;.</dd>\n      <dt id="all"><a class="permalink" href="#all"><code class="Cm">all</code></a></dt>\n      <dd>Acts like <code class="Cm">equ,var,equs,char,macro</code>.</dd>\n    </dl>\n    <p class="Pp">This flag may be specified multiple times with different\n        feature subsets to write them to different files (see\n        <a class="Sx" href="#EXAMPLES">EXAMPLES</a> below).</p>\n  </dd>\n  <dt id="V"><a class="permalink" href="#V"><code class="Fl">-V</code></a>,\n    <code class="Fl">--version</code></dt>\n  <dd>Print the version of the program and exit.</dd>\n  <dt id="v"><a class="permalink" href="#v"><code class="Fl">-v</code></a>,\n    <code class="Fl">--verbose</code></dt>\n  <dd>Be verbose.</dd>\n  <dt id="W"><a class="permalink" href="#W"><code class="Fl">-W</code></a>\n    <var class="Ar">warning</var>, <code class="Fl">--warning</code>\n    <var class="Ar">warning</var></dt>\n  <dd>Set warning flag <var class="Ar">warning</var>. A warning message will be\n      printed if <var class="Ar">warning</var> is an unknown warning flag. See\n      the <a class="Sx" href="#DIAGNOSTICS">DIAGNOSTICS</a> section for a list\n      of warnings.</dd>\n  <dt id="w"><a class="permalink" href="#w"><code class="Fl">-w</code></a></dt>\n  <dd>Disable all warning output, even when turned into errors.</dd>\n  <dt id="X"><a class="permalink" href="#X"><code class="Fl">-X</code></a>\n    <var class="Ar">max_errors</var>, <code class="Fl">--max-errors</code>\n    <var class="Ar">max_errors</var></dt>\n  <dd>If more than this number of errors (not warnings) occur, then abort the\n      assembly process; <code class="Fl">-X</code> <var class="Ar">0</var>\n      disables this behavior. The default is 100 if\n      <code class="Nm">rgbasm</code> is printing errors to a terminal, and 0\n      otherwise.</dd>\n</dl>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="DIAGNOSTICS"><a class="permalink" href="#DIAGNOSTICS">DIAGNOSTICS</a></h2>\n<p class="Pp">Warnings are diagnostic messages that indicate possibly erroneous\n    behavior that does not necessarily compromise the assembling process. The\n    following options alter the way warnings are processed.</p>\n<dl class="Bl-tag">\n  <dt id="Werror"><a class="permalink" href="#Werror"><code class="Fl">-Werror</code></a></dt>\n  <dd>Make all warnings into errors. This can be negated as\n      <code class="Fl">-Wno-error</code> to prevent turning all warnings into\n      errors.</dd>\n  <dt id="Werror="><a class="permalink" href="#Werror="><code class="Fl">-Werror=</code></a></dt>\n  <dd>Make the specified warning or meta warning into an error. A warning\'s name\n      is appended (example: <code class="Fl">-Werror=obsolete</code>), and this\n      warning is implicitly enabled and turned into an error. This can be\n      negated as <code class="Fl">-Wno-error=</code> to prevent turning a\n      specified warning into an error, even if <code class="Fl">-Werror</code>\n      is in effect.</dd>\n</dl>\n<p class="Pp">The following warnings are &#x201C;meta&#x201D; warnings, that\n    enable a collection of other warnings. If a specific warning is toggled via\n    a meta flag and a specific one, the more specific one takes priority. The\n    position on the command-line acts as a tie breaker, the last one taking\n    effect.</p>\n<dl class="Bl-tag">\n  <dt id="Wall"><a class="permalink" href="#Wall"><code class="Fl">-Wall</code></a></dt>\n  <dd>This enables warnings that are likely to indicate an error or undesired\n      behavior, and that can easily be fixed.</dd>\n  <dt id="Wextra"><a class="permalink" href="#Wextra"><code class="Fl">-Wextra</code></a></dt>\n  <dd>This enables extra warnings that are less likely to pose a problem, but\n      that may still be wanted.</dd>\n  <dt id="Weverything"><a class="permalink" href="#Weverything"><code class="Fl">-Weverything</code></a></dt>\n  <dd>Enables literally every warning.</dd>\n</dl>\n<p class="Pp">The following warnings are actual warning flags; with each\n    description, the corresponding warning flag is included. Note that each of\n    these flag also has a negation (for example,\n    <code class="Fl">-Wcharmap-redef</code> enables the warning that\n    <code class="Fl">-Wno-charmap-redef</code> disables; and\n    <code class="Fl">-Wall</code> enables every warning that\n    <code class="Fl">-Wno-all</code> disables). Only the non-default flag is\n    listed here. Ignoring the &#x201C;no-&#x201D; prefix, entries are listed\n    alphabetically.</p>\n<dl class="Bl-tag">\n  <dt id="Wno-assert"><a class="permalink" href="#Wno-assert"><code class="Fl">-Wno-assert</code></a></dt>\n  <dd>Warn when <code class="Ic">WARN</code><span class="No">-type</span>\n      assertions fail. (See &#x201C;Aborting the assembly process&#x201D; in\n      <a class="Xr" href="./rgbasm.5">rgbasm(5)</a> for\n      <code class="Ic">ASSERT</code>).</dd>\n  <dt id="Wbackwards-for"><a class="permalink" href="#Wbackwards-for"><code class="Fl">-Wbackwards-for</code></a></dt>\n  <dd>Warn when <code class="Ic">FOR</code> loops have their start and stop\n      values switched according to the step value. This warning is enabled by\n      <code class="Fl">-Wall</code>.</dd>\n  <dt id="Wbuiltin-args"><a class="permalink" href="#Wbuiltin-args"><code class="Fl">-Wbuiltin-args</code></a></dt>\n  <dd>Warn about incorrect arguments to built-in functions, such as\n      <code class="Fn">STRSUB</code>() with indexes outside of the string\'s\n      bounds. This warning is enabled by <code class="Fl">-Wall</code>.</dd>\n  <dt id="Wcharmap-redef"><a class="permalink" href="#Wcharmap-redef"><code class="Fl">-Wcharmap-redef</code></a></dt>\n  <dd>Warn when re-defining a charmap mapping. This warning is enabled by\n      <code class="Fl">-Wall</code>.</dd>\n  <dt id="Wdiv"><a class="permalink" href="#Wdiv"><code class="Fl">-Wdiv</code></a></dt>\n  <dd>Warn when dividing the smallest negative integer (-2**31) by -1, which\n      yields itself due to integer overflow.</dd>\n  <dt id="Wempty-macro-arg"><a class="permalink" href="#Wempty-macro-arg"><code class="Fl">-Wempty-macro-arg</code></a></dt>\n  <dd>Warn when a macro argument is empty. This warning is enabled by\n      <code class="Fl">-Wextra</code>.</dd>\n  <dt id="Wempty-strrpl"><a class="permalink" href="#Wempty-strrpl"><code class="Fl">-Wempty-strrpl</code></a></dt>\n  <dd>Warn when <code class="Fn">STRRPL</code>() is called with an empty string\n      as its second argument (the substring to replace). This warning is enabled\n      by <code class="Fl">-Wall</code>.</dd>\n  <dt id="Wlarge-constant"><a class="permalink" href="#Wlarge-constant"><code class="Fl">-Wlarge-constant</code></a></dt>\n  <dd>Warn when a constant too large to fit in a signed 32-bit integer is\n      encountered. This warning is enabled by\n    <code class="Fl">-Wall</code>.</dd>\n  <dt id="Wmacro-shift"><a class="permalink" href="#Wmacro-shift"><code class="Fl">-Wmacro-shift</code></a></dt>\n  <dd>Warn when shifting macro arguments past their limits. This warning is\n      enabled by <code class="Fl">-Wextra</code>.</dd>\n  <dt id="Wno-nested-comment"><a class="permalink" href="#Wno-nested-comment"><code class="Fl">-Wno-nested-comment</code></a></dt>\n  <dd>Warn when the block comment start sequence\n      &#x2018;<code class="Li">/*</code>&#x2019; is found inside of a block\n      comment. Block comments cannot be nested, so the first\n      &#x2018;<code class="Li">*/</code>&#x2019; will end the whole\n    comment.</dd>\n  <dt id="Wno-obsolete"><a class="permalink" href="#Wno-obsolete"><code class="Fl">-Wno-obsolete</code></a></dt>\n  <dd>Warn when obsolete constructs such as the <code class="Ic">_PI</code>\n      constant or <code class="Ic">PRINTT</code> directive are encountered.</dd>\n  <dt id="Wnumeric-string="><a class="permalink" href="#Wnumeric-string="><code class="Fl">-Wnumeric-string=</code></a></dt>\n  <dd>Warn when a multi-character string is treated as a number.\n      <code class="Fl">-Wnumeric-string=0</code> or\n      <code class="Fl">-Wno-numeric-string</code> disables this warning.\n      <code class="Fl">-Wnumeric-string=1</code> or just\n      <code class="Fl">-Wnumeric-string</code> warns about strings longer than\n      four characters, since four or fewer characters fit within a 32-bit\n      integer. <code class="Fl">-Wnumeric-string=2</code> warns about any\n      multi-character string.</dd>\n  <dt id="Wpurge="><a class="permalink" href="#Wpurge="><code class="Fl">-Wpurge=</code></a></dt>\n  <dd>Warn when purging symbols which are likely to have been necessary.\n      <code class="Fl">-Wpurge=0</code> or <code class="Fl">-Wno-purge</code>\n      disables this warning. <code class="Fl">-Wpurge=1</code> or just\n      <code class="Fl">-Wpurge</code> warns when purging any exported symbol\n      (regardless of type). <code class="Fl">-Wpurge=2</code> also warns when\n      purging any label (even if not exported).</dd>\n  <dt id="Wshift"><a class="permalink" href="#Wshift"><code class="Fl">-Wshift</code></a></dt>\n  <dd>Warn when shifting right a negative value. Use a division by 2**N\n    instead.</dd>\n  <dt id="Wshift-amount"><a class="permalink" href="#Wshift-amount"><code class="Fl">-Wshift-amount</code></a></dt>\n  <dd>Warn when a shift\'s operand is negative or greater than 32.</dd>\n  <dt id="Wtruncation="><a class="permalink" href="#Wtruncation="><code class="Fl">-Wtruncation=</code></a></dt>\n  <dd>Warn when an implicit truncation (for example, <code class="Ic">db</code>\n      to an 8-bit value) loses some bits. <code class="Fl">-Wtruncation=0</code>\n      or <code class="Fl">-Wno-truncation</code> disables this warning.\n      <code class="Fl">-Wtruncation=1</code> warns when an N-bit value is 2**N\n      or greater, or less than -2**N. <code class="Fl">-Wtruncation=2</code> or\n      just <code class="Fl">-Wtruncation</code> also warns when an N-bit value\n      is less than -2**(N-1), which will not fit in two\'s complement\n    encoding.</dd>\n  <dt id="Wunmapped-char="><a class="permalink" href="#Wunmapped-char="><code class="Fl">-Wunmapped-char=</code></a></dt>\n  <dd>Warn when a character goes through charmap conversion but has no defined\n      mapping. <code class="Fl">-Wunmapped-char=0</code> or\n      <code class="Fl">-Wno-unmapped-char</code> disables this warning.\n      <code class="Fl">-Wunmapped-char=1</code> or just\n      <code class="Fl">-Wunmapped-char</code> only warns if the active charmap\n      is not empty. <code class="Fl">-Wunmapped-char=2</code> warns if the\n      active charmap is empty, and/or is not the default charmap\n      &#x2018;main&#x2019;.</dd>\n  <dt id="Wunmatched-directive"><a class="permalink" href="#Wunmatched-directive"><code class="Fl">-Wunmatched-directive</code></a></dt>\n  <dd>Warn when a <code class="Ic">PUSHC</code>, <code class="Ic">PUSHO</code>,\n      or <code class="Ic">PUSHS</code> directive does not have a corresponding\n      <code class="Ic">POPC</code>, <code class="Ic">POPO</code>, or\n      <code class="Ic">POPS</code>. This warning is enabled by\n      <code class="Fl">-Wextra</code>.</dd>\n  <dt id="Wunterminated-load"><a class="permalink" href="#Wunterminated-load"><code class="Fl">-Wunterminated-load</code></a></dt>\n  <dd>Warn when a <code class="Ic">LOAD</code> block is not terminated by an\n      <code class="Ic">ENDL</code>. This warning is enabled by\n      <code class="Fl">-Wextra</code>.</dd>\n  <dt id="Wno-user"><a class="permalink" href="#Wno-user"><code class="Fl">-Wno-user</code></a></dt>\n  <dd>Warn when the <code class="Ic">WARN</code> built-in is executed. (See\n      &#x201C;Aborting the assembly process&#x201D; in\n      <a class="Xr" href="./rgbasm.5">rgbasm(5)</a> for\n      <code class="Ic">WARN</code>).</dd>\n</dl>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="EXAMPLES"><a class="permalink" href="#EXAMPLES">EXAMPLES</a></h2>\n<p class="Pp">You can assemble a source file in two ways.</p>\n<p class="Pp">Straightforward way:</p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbasm -o bar.o\n  foo.asm</code></div>\n<p class="Pp">Pipes way:</p>\n<div class="Bd Bd-indent"><code class="Li">$ cat foo.asm | rgbasm -o bar.o\n  -</code></div>\n<div class="Bd Bd-indent"><code class="Li">$ rgbasm -o bar.o - &lt;\n  foo.asm</code></div>\n<p class="Pp">The resulting object file is not yet a usable ROM image&#x2014;it\n    must first be run through <a class="Xr" href="./rgblink.1">rgblink(1)</a>\n    and then <a class="Xr" href="./rgbfix.1">rgbfix(1)</a>.</p>\n<p class="Pp">Writing the final assembler state to a file:</p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbasm -s all:state.dump.asm\n  foo.asm</code></div>\n<p class="Pp">Or to multiple files:</p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbasm -s equ,var:numbers.dump.asm\n  -s equs:strings.dump.asm foo.asm</code></div>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="BUGS"><a class="permalink" href="#BUGS">BUGS</a></h2>\n<p class="Pp">Please report bugs on\n    <a class="Lk" href="https://github.com/gbdev/rgbds/issues">GitHub</a>.</p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="SEE_ALSO"><a class="permalink" href="#SEE_ALSO">SEE\n  ALSO</a></h2>\n<p class="Pp"><a class="Xr" href="./rgbasm.5">rgbasm(5)</a>,\n    <a class="Xr" href="./rgblink.1">rgblink(1)</a>,\n    <a class="Xr" href="./rgbfix.1">rgbfix(1)</a>,\n    <a class="Xr" href="./rgbgfx.1">rgbgfx(1)</a>,\n    <a class="Xr" href="./gbz80.7">gbz80(7)</a>,\n    <a class="Xr" href="./rgbasm-old.5">rgbasm-old(5)</a>,\n    <a class="Xr" href="./rgbds.5">rgbds(5)</a>,\n    <a class="Xr" href="./rgbds.7">rgbds(7)</a></p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="HISTORY"><a class="permalink" href="#HISTORY">HISTORY</a></h2>\n<p class="Pp"><code class="Nm">rgbasm</code> was originally written by\n    <span class="An">Carsten S&#x00F8;rensen</span> as part of the ASMotor\n    package, and was later repackaged in RGBDS by <span class="An">Justin\n    Lloyd</span>. It is now maintained by a number of contributors at\n    <a class="Lk" href="https://github.com/gbdev/rgbds">https://github.com/gbdev/rgbds</a>.</p>\n</section>\n',l={},o="rgbasm(1) \u2014 Game Boy assembler",t={},i=[{value:"SYNOPSIS",id:"SYNOPSIS",level:2},{value:"DESCRIPTION",id:"DESCRIPTION",level:2},{value:"DIAGNOSTICS",id:"DIAGNOSTICS",level:2},{value:"EXAMPLES",id:"EXAMPLES",level:2},{value:"BUGS",id:"BUGS",level:2},{value:"SEE ALSO",id:"SEE_ALSO",level:2},{value:"HISTORY",id:"HISTORY",level:2}];function h(e){const a={h1:"h1",header:"header",...(0,d.R)(),...e.components};return(0,c.jsxs)(c.Fragment,{children:[(0,c.jsx)(a.header,{children:(0,c.jsx)(a.h1,{id:"rgbasm1--game-boy-assembler",children:"rgbasm(1) \u2014 Game Boy assembler"})}),"\n","\n",(0,c.jsx)("div",{className:"manual-text",dangerouslySetInnerHTML:{__html:r}})]})}function m(e={}){const{wrapper:a}={...(0,d.R)(),...e.components};return a?(0,c.jsx)(a,{...e,children:(0,c.jsx)(h,{...e})}):h(e)}}}]);